files.Makefile:
folder: ## create folder structure
	@mkdir -p docs
	@mkdir -p pb
	@mkdir -p proto
	@mkdir -p vendor
mod: ## Install go library
	@go mod tidy
	@go mod vendor

run: ##run code 
	@statik -f -src=docs -dest=cmd/server && go run ./cmd/main.go

build-statik: ##build statik file
	@statik -f -src=docs -dest=cmd/server

build: ## build application to binary file
	cd ./cmd && go build -o repayment_service .

install: ## install protobuf
	@go install github.com/mwitkow/go-proto-validators/protoc-gen-govalidators@latest
	@go install	github.com/grpc-ecosystem/grpc-gateway/v2/protoc-gen-grpc-gateway@latest
	@go install	github.com/grpc-ecosystem/grpc-gateway/v2/protoc-gen-openapiv2@latest
	@go install	google.golang.org/grpc/cmd/protoc-gen-go-grpc@latest
	@go install	google.golang.org/protobuf/cmd/protoc-gen-go@latest
	@go install	github.com/rakyll/statik@latest
	@go install	github.com/vektra/mockery/v2@latest
	@go install github.com/grpc-ecosystem/grpc-gateway/v2@latest
	@go install google.golang.org/protobuf@latest
	@go install google.golang.org/grpc@latest
	@go install google.golang.org/genproto@latest
	@go install github.com/envoyproxy/protoc-gen-validate@latest

generate:## Generate proto
	protoc \
    -I proto/ \
    -I $(GOPATH)/pkg/mod/google.golang.org/ \
    -I $(GOPATH)/pkg/mod/github.com/grpc-ecosystem/grpc-gateway \
    -I $(GOPATH)/pkg/mod/github.com/envoyproxy/protoc-gen-validate@v1.2.1/ \
    --plugin=$(GOBIN)/protoc-gen-go \
    --plugin=$(GOBIN)/protoc-gen-go-grpc \
    --plugin=$(GOBIN)/protoc-gen-openapiv2 \
    --plugin=$(GOBIN)/protoc-gen-grpc-gateway \
    --go_out=paths=source_relative:./pb \
    --go-grpc_out=paths=source_relative,require_unimplemented_servers=false:./pb \
    --validate_out="lang=go,paths=source_relative:./pb" \
    --grpc-gateway_out=paths=source_relative:./pb \
    --openapiv2_out=docs \
    --proto_path=proto \
    proto/*.proto

test: ## Run test for whole project
	@go test -v ./...

install-oracle-instantclient: ## Install Oracle Instant Client
	@bash third_party/oracle/oracle-instantclient.sh

help: ## Display this help screen
	@grep -E '^[a-zA-Z_-]+:.*?## .*$$' $(MAKEFILE_LIST) | sort | awk 'BEGIN {FS = ":.*?## "}; {printf "\033[36m%-30s\033[0m %s\n", $$1, $$2}'

clean: ## delete docs swagger and proto file
	@rm pb/*.go

env: ##install env for protobuf
	@export PATH=$PATH:/usr/local/bin:/root/go/bin:/usr/local/go/bin
	@export GOINSECURE=vtt-git-01.deltavn.vn
	@export GOPRIVATE=vtt-git-01.deltavn.vn/esb_microservices

mock: ## generate code to unit test
	@mockery --dir ./internal/helper --name RedisCacheHelper --output ./internal/helper/mocks --filename cache.go
	@mockery --dir ./internal/repository --name IRepaymentRepository --output ./internal/repository/mocks --filename repayment_repo.go

lint:
	@golangci-lint run ./...

