package client

import (
	"context"
	"sync"
	"time"

	"fec_pool_service/pb"

	grpc_retry "github.com/grpc-ecosystem/go-grpc-middleware/retry"
	"go.uber.org/zap"
	"google.golang.org/grpc"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/connectivity"
	"google.golang.org/grpc/credentials/insecure"
	"google.golang.org/grpc/keepalive"
	"google.golang.org/grpc/status"
)

type (
	ClientPoolServiceImpl struct {
		conn   *grpc.ClientConn
		client pb.PoolAPIClient
		mu     sync.RWMutex
		addr   string
	}

	IClientPoolService interface {
		PoolExecuteQuery(ctx context.Context, req *pb.PoolExecuteQueryRequest) (*pb.PoolExecuteQueryResponse, error)
		GetConn() *grpc.ClientConn
		Close()
	}
)

// NewPoolServerClient creates a new gRPC client with retry and reconnect capabilities
func NewPoolServerClient(grpcAddress string) (IClientPoolService, error) {

	retryOpts := []grpc_retry.CallOption{
		grpc_retry.WithMax(3), // retry max 3 times
		grpc_retry.WithBackoff(grpc_retry.BackoffExponential(100 * time.Millisecond)),   // Backoff 100ms
		grpc_retry.WithCodes(codes.Canceled, codes.Unavailable, codes.DeadlineExceeded), // Retry with these grpc code
	}

	conn, err := grpc.NewClient(
		grpcAddress,
		grpc.WithTransportCredentials(insecure.NewCredentials()),
		grpc.WithKeepaliveParams(keepalive.ClientParameters{
			Time:                10 * time.Second, // ping each 10 sec
			Timeout:             5 * time.Second,  // ping wait 5 sec
			PermitWithoutStream: true,             // allow ping when no stream
		}),
		grpc.WithUnaryInterceptor(grpc_retry.UnaryClientInterceptor(retryOpts...)),
	)
	if err != nil {
		zap.L().Error("Can't connect to gRPC server", zap.String("Error msg", err.Error()))
		return nil, err
	}

	return &ClientPoolServiceImpl{
		conn:   conn,
		client: pb.NewPoolAPIClient(conn),
		addr:   grpcAddress,
	}, nil
}

// reconnect attempts to re-establish the gRPC connection if it's closed
func (c *ClientPoolServiceImpl) reconnect() error {
	c.mu.Lock()
	defer c.mu.Unlock()

	// check connection status
	if c.conn.GetState() != connectivity.Shutdown && c.conn.GetState() != connectivity.TransientFailure {
		return nil
	}

	zap.L().Info("Reconnecting to gRPC server", zap.String("Address", c.addr))
	// close old connection
	c.conn.Close()

	// config retry to new connection
	retryOpts := []grpc_retry.CallOption{
		grpc_retry.WithMax(3),
		grpc_retry.WithBackoff(grpc_retry.BackoffExponential(100 * time.Millisecond)),
		grpc_retry.WithCodes(codes.Canceled, codes.Unavailable, codes.DeadlineExceeded),
	}

	// create new connection
	conn, err := grpc.NewClient(
		c.addr,
		grpc.WithTransportCredentials(insecure.NewCredentials()),
		grpc.WithKeepaliveParams(keepalive.ClientParameters{
			Time:                10 * time.Second,
			Timeout:             5 * time.Second,
			PermitWithoutStream: true,
		}),
		grpc.WithUnaryInterceptor(grpc_retry.UnaryClientInterceptor(retryOpts...)),
	)
	if err != nil {
		zap.L().Error("Reconnect failed", zap.String("Error msg", err.Error()))
		return err
	}

	// update connection to client
	c.conn = conn
	c.client = pb.NewPoolAPIClient(conn)
	zap.L().Info("Reconnected successfully", zap.String("Address", c.addr))
	return nil
}

// getClient returns current client under read lock
func (c *ClientPoolServiceImpl) getClient() pb.PoolAPIClient {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return c.client
}

// getConnState returns connection state under read lock
func (c *ClientPoolServiceImpl) getConnState() connectivity.State {
	c.mu.RLock()
	defer c.mu.RUnlock()
	if c.conn == nil {
		return connectivity.Shutdown
	}
	return c.conn.GetState()
}

// PoolExecuteQuery sends a gRPC request with retry and reconnect logic
func (c *ClientPoolServiceImpl) PoolExecuteQuery(ctx context.Context, req *pb.PoolExecuteQueryRequest) (*pb.PoolExecuteQueryResponse, error) {
	zap.L().Info("Calling Pool Service ExecuteQuery", zap.String("TransID", req.Sys.TransId))

	// Check and reconnect if needed
	if state := c.getConnState(); state == connectivity.Shutdown || state == connectivity.TransientFailure {
		if err := c.reconnect(); err != nil {
			zap.L().Error("Failed to reconnect before request", zap.String("TransID", req.Sys.TransId), zap.Error(err))
			return nil, err
		}
	}

	// Snapshot client under RLock
	client := c.getClient()
	resp, err := client.ExecuteQuery(ctx, req)
	if err != nil {
		zap.L().Error("ExecuteQuery failed", zap.String("TransID", req.Sys.TransId), zap.Error(err))

		if st, ok := status.FromError(err); ok && (st.Code() == codes.Unavailable || st.Code() == codes.Canceled) {
			if reconnectErr := c.reconnect(); reconnectErr != nil {
				zap.L().Error("Reconnect failed after request error", zap.String("TransID", req.Sys.TransId), zap.Error(reconnectErr))
				return nil, err
			}
			// Get new client after reconnect
			client = c.getClient()
			resp, err = client.ExecuteQuery(ctx, req)
			if err != nil {
				zap.L().Error("ExecuteQuery failed after reconnect", zap.String("TransID", req.Sys.TransId), zap.Error(err))
				return nil, err
			}
		} else {
			return nil, err
		}
	}

	zap.L().Info("ExecuteQuery successful", zap.String("TransID", req.Sys.TransId))
	return resp, nil
}

// GetConn returns the underlying gRPC client connection for health/readiness checks
func (c *ClientPoolServiceImpl) GetConn() *grpc.ClientConn {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return c.conn
}

// Close closes the gRPC connection
func (c *ClientPoolServiceImpl) Close() {
	c.mu.Lock()
	defer c.mu.Unlock()
	if c.conn != nil {
		c.conn.Close()
		c.conn = nil
		zap.L().Info("gRPC connection closed", zap.String("Address", c.addr))
	}
}

