package client

import (
	"testing"

	"google.golang.org/grpc"
	"google.golang.org/grpc/connectivity"
	"google.golang.org/grpc/credentials/insecure"
)

// Compile-time check: ClientPoolServiceImpl must implement IClientPoolService
var _ IClientPoolService = (*ClientPoolServiceImpl)(nil)

func newTestConn(t *testing.T) *grpc.ClientConn {
	t.Helper()
	conn, err := grpc.NewClient("localhost:0", grpc.WithTransportCredentials(insecure.NewCredentials()))
	if err != nil {
		t.Fatalf("failed to create test conn: %v", err)
	}
	return conn
}

func TestGetConn_ReturnsConnection(t *testing.T) {
	conn := newTestConn(t)
	defer conn.Close()

	impl := &ClientPoolServiceImpl{conn: conn, addr: "localhost:0"}
	got := impl.GetConn()

	if got == nil {
		t.Fatal("GetConn() returned nil, expected a valid *grpc.ClientConn")
	}
	if got != conn {
		t.Fatal("GetConn() returned a different connection than expected")
	}
}

func TestGetConn_StateAvailableForReadyz(t *testing.T) {
	conn := newTestConn(t)
	defer conn.Close()

	impl := &ClientPoolServiceImpl{conn: conn, addr: "localhost:0"}
	got := impl.GetConn()

	state := got.GetState()
	// A newly created connection (no real server) should be Idle
	if state != connectivity.Idle {
		t.Fatalf("expected Idle state for new conn, got %v", state)
	}
}

func TestGetConn_NilAfterClose(t *testing.T) {
	conn := newTestConn(t)

	impl := &ClientPoolServiceImpl{conn: conn, addr: "localhost:0"}
	impl.Close()

	got := impl.GetConn()
	if got != nil {
		t.Fatal("GetConn() should return nil after Close()")
	}
}

// Simulate the readyz check pattern that importing projects will use
func TestReadyzPattern(t *testing.T) {
	conn := newTestConn(t)
	defer conn.Close()

	var svc IClientPoolService = &ClientPoolServiceImpl{conn: conn, addr: "localhost:0"}

	grpcConn := svc.GetConn()
	state := grpcConn.GetState()

	// Idle and Ready are both considered healthy for readyz
	if state != connectivity.Idle && state != connectivity.Ready {
		t.Fatalf("readyz check failed: connection state is %v", state)
	}
}

