package api

import (
	"context"
	"crypto/subtle"
	"database/sql"
	"encoding/base64"
	"errors"
	utilLib "esb-go-libs/util"
	"fec_pool_service/config"
	"fec_pool_service/internal/common"
	"fec_pool_service/internal/dto"
	"fec_pool_service/internal/usecase"
	"fec_pool_service/internal/util"
	"fec_pool_service/pb"
	"strings"
	"time"

	"go.elastic.co/apm/v2"
	"go.uber.org/zap"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/metadata"
	"google.golang.org/grpc/status"
)

const HttpCodeHeader = "X-Http-Code"

type (
	api struct {
		cfg         *config.Config
		pbConverter utilLib.PbConverter
		useCase     usecase.IFecPoolServiceUseCase
		workerPool  chan struct{}
	}
)

func NewAPI(
	cfg *config.Config,
	pbConverter utilLib.PbConverter,
	useCase usecase.IFecPoolServiceUseCase,
) pb.PoolAPIServer {
	return &api{
		cfg:         cfg,
		pbConverter: pbConverter,
		useCase:     useCase,
		workerPool:  make(chan struct{}, cfg.OracleDB.MaxConn),
	}
}

func (a *api) AuthFuncOverride(ctx context.Context, fullMethodName string) (context.Context, error) {
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return nil, status.Newf(codes.Unauthenticated, "Unauthorized: missing metadata").Err()
	}

	authorization, ok := md["authorization"]
	if !ok || len(authorization) == 0 || authorization[0] == "" {
		return nil, status.Newf(codes.Unauthenticated, "Unauthorized").Err()
	}
	authorizationArrays := strings.Split(authorization[0], " ")
	if len(authorizationArrays) != 2 || authorizationArrays[0] != "Basic" {
		return nil, status.Newf(codes.Unauthenticated, "Unauthorized").Err()
	}
	// Authenticate
	usernameAndPassword, err := base64.StdEncoding.DecodeString(authorizationArrays[1])
	if err != nil {
		return nil, status.Newf(codes.Unauthenticated, "Unauthorized").Err()
	}
	usernameAndPasswordArrays := strings.Split(string(usernameAndPassword), ":")
	if len(usernameAndPasswordArrays) != 2 {
		return nil, status.Newf(codes.Unauthenticated, "Unauthorized").Err()
	}

	password, ok := a.cfg.Auth.Authentications[usernameAndPasswordArrays[0]]
	if !ok || subtle.ConstantTimeCompare([]byte(usernameAndPasswordArrays[1]), []byte(password)) != 1 {
		return nil, status.Newf(codes.Unauthenticated, "Unauthorized").Err()
	}

	return ctx, nil
}

func (a *api) ExecuteQuery(ctx context.Context, req *pb.PoolExecuteQueryRequest) (*pb.PoolExecuteQueryResponse, error) {
	span, ctx := apm.StartSpan(ctx, "fec-ws-pool-service.api.PoolExecuteQuery", a.cfg.OracleDB.Host)
	defer span.End()
	span.Context.SetLabel("TransID", req.Sys.TransId)

	queryDTO := &dto.ExecuteQueryRequestDTO{}
	a.pbConverter.FromPbToInterface(queryDTO, req)
	zap.L().Info("Processing request data", zap.Any("InputRequest", queryDTO), zap.String("TransID", queryDTO.Sys.TransID))

	select {
	case a.workerPool <- struct{}{}:
		// Slot acquired — release trong goroutine khi query thực sự hoàn thành
	case <-ctx.Done():
		zap.L().Error("Timeout waiting for worker pool slot", zap.String("TransID", req.Sys.TransId))
		errTW := errors.New("timeout waiting for worker pool slot")
		return a.buildResponse(req.Sys.TransId, common.ReasonAdapterTimeout, "", errTW), errTW
	}

	resultChan := make(chan *dto.ExecuteQueryResponseDTO, 1)
	go func() {
		defer func() { <-a.workerPool }() // release slot khi goroutine xong
		defer close(resultChan)
		defer func() {
			if r := recover(); r != nil {
				zap.L().Error("Panic recovered in ExecuteQuery goroutine",
					zap.String("TransID", req.Sys.TransId),
					zap.Any("panic", r),
					zap.Stack("stacktrace"),
				)
			}
		}()
		rs := a.useCase.ExecuteQuery(ctx, queryDTO, req.Sys.TransId)

		select {
		case resultChan <- rs:
		case <-ctx.Done():
			zap.L().Warn("Context cancelled during ExecuteQuery, result discarded", zap.String("TransID", req.Sys.TransId))
		}
	}()

	select {
	case result, ok := <-resultChan:
		if !ok {
			// channel closed unexpectedly such as goroutine panic
			zap.L().Error("Result channel closed unexpectedly", zap.String("TransID", req.Sys.TransId))
			errRCC := errors.New("result channel closed unexpectedly")
			return a.buildResponse(req.Sys.TransId, common.ReasonAdapterError, "", errRCC), errRCC
		}
		return a.handleQueryResult(req.Sys.TransId, result)

	case <-ctx.Done():
		// Timeout when waiting for ExecuteQuery result
		zap.L().Error("Timeout when called ExecuteQuery", zap.String("TransID", req.Sys.TransId))
		errTO := status.Errorf(codes.DeadlineExceeded, "timeout when called ExecuteQuery")
		return a.buildResponse(req.Sys.TransId, common.ReasonAdapterTimeout, "", errors.New("timeout when called ExecuteQuery")), errTO
	}
}

// handleQueryResult process use case result and create response.
func (a *api) handleQueryResult(transID string, result *dto.ExecuteQueryResponseDTO) (*pb.PoolExecuteQueryResponse, error) {
	//Error cases
	if result.Error != nil {
		if result.Error == sql.ErrNoRows {
			// NO_DATA_FOUND
			zap.L().Debug("Result ExecuteQuery", zap.String("TransID", transID), zap.String("Result", "NO_DATA_FOUND"))
			return a.buildResponse(transID, common.ReasonDataNotFound, "", nil), nil
		}
		// Others errors
		zap.L().Error("Error from ExecuteQuery", zap.String("TransID", transID), zap.String("ErrorMsg", result.Error.Error()))
		return a.buildResponse(transID, common.ReasonAdapterError, "", errors.New("error from ExecuteQuery")), nil
	}

	//Success cases
	strResult, err := util.ToJSON(result.OutParams)
	if err != nil {
		zap.L().Error("Failed to marshal result to JSON", zap.String("TransID", transID), zap.String("ErrorMsg", err.Error()))
		return a.buildResponse(transID, common.ReasonAdapterError, "", errors.New("failed to marshal result to JSON")), nil
	}

	zap.L().Info("Result ExecuteQuery", zap.String("TransID", transID), zap.String("Result", util.TruncatedString(strResult, 1000)))

	if len(result.OutParams) > 0 {
		return a.buildResponse(transID, common.ReasonDataFound, strResult, nil), nil
	}
	return a.buildResponse(transID, common.ReasonDataNotFound, strResult, nil), nil
}

// buildResponse create response for pool service
func (a *api) buildResponse(transID string, rc common.ReasonCode, results string, err error) *pb.PoolExecuteQueryResponse {
	rs := &pb.PoolExecuteQueryResponse{
		Sys: &pb.PoolSysResp{
			TransId:     transID,
			DateTime:    time.Now().Format(time.RFC3339Nano),
			Code:        util.ConvertStrToInt32(rc.Code()),
			Description: rc.Message(),
		},
		Results: results,
	}
	if err != nil {
		rs.Sys.Description = rc.Message() + " : " + err.Error()
	}
	return rs
}

