files.internal/health/health.go:
package health

import (
	"context"
	"encoding/json"
	"net/http"
	"sync"
	"time"

	"go.uber.org/zap"
	"google.golang.org/grpc"
	"google.golang.org/grpc/connectivity"
)

// Status represents the health status of a component.
type Status string

const (
	StatusUp   Status = "UP"
	StatusDown Status = "DOWN"
)

type ComponentStatus struct {
	Status  Status `json:"status"`
	Message string `json:"message,omitempty"`
}

type HealthResponse struct {
	Status     Status                     `json:"status"`
	Components map[string]ComponentStatus `json:"components,omitempty"`
}

// Checker holds references to dependencies for health checking.
type Checker struct {
	mu              sync.RWMutex
	grpcConn        *grpc.ClientConn
	grpcTarget      string
	ready           bool
	startupComplete bool
}

func NewChecker() *Checker {
	return &Checker{}
}

// SetGRPCConn registers the gRPC client connection for readiness checks.
func (c *Checker) SetGRPCConn(conn *grpc.ClientConn, target string) {
	c.mu.Lock()
	defer c.mu.Unlock()
	c.grpcConn = conn
	c.grpcTarget = target
}

// SetReady marks the service as ready to receive traffic.
func (c *Checker) SetReady(ready bool) {
	c.mu.Lock()
	defer c.mu.Unlock()
	c.ready = ready
}

// SetStartupComplete marks that initial startup has finished.
func (c *Checker) SetStartupComplete(done bool) {
	c.mu.Lock()
	defer c.mu.Unlock()
	c.startupComplete = done
}

// LivenessHandler returns HTTP 200 if the process is alive.
// K8s uses this to decide whether to restart the container.
func (c *Checker) LivenessHandler() http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		resp := HealthResponse{
			Status: StatusUp,
		}
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		json.NewEncoder(w).Encode(resp)
	}
}

// ReadinessHandler returns HTTP 200 only when all dependencies are healthy.
// K8s uses this to decide whether to send traffic to this pod.
func (c *Checker) ReadinessHandler() http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		c.mu.RLock()
		defer c.mu.RUnlock()

		components := make(map[string]ComponentStatus)
		allHealthy := true

		// Check startup complete
		if !c.startupComplete {
			allHealthy = false
			components["startup"] = ComponentStatus{
				Status:  StatusDown,
				Message: "service is still starting up",
			}
		} else {
			components["startup"] = ComponentStatus{Status: StatusUp}
		}

		// Check ready flag
		if !c.ready {
			allHealthy = false
			components["service"] = ComponentStatus{
				Status:  StatusDown,
				Message: "service is not ready",
			}
		} else {
			components["service"] = ComponentStatus{Status: StatusUp}
		}

		// Check gRPC connection
		if c.grpcConn != nil {
			state := c.grpcConn.GetState()
			switch state {
			case connectivity.Ready, connectivity.Idle:
				components["grpc_connection"] = ComponentStatus{
					Status:  StatusUp,
					Message: state.String(),
				}
			default:
				allHealthy = false
				components["grpc_connection"] = ComponentStatus{
					Status:  StatusDown,
					Message: state.String(),
				}
			}
		}

		resp := HealthResponse{
			Components: components,
		}

		if allHealthy {
			resp.Status = StatusUp
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusOK)
		} else {
			resp.Status = StatusDown
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusServiceUnavailable)
		}
		json.NewEncoder(w).Encode(resp)
	}
}

// StartupHandler returns HTTP 200 once initial startup is complete.
// K8s uses this with startupProbe to give slow-starting containers time.
func (c *Checker) StartupHandler() http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		c.mu.RLock()
		defer c.mu.RUnlock()

		if c.startupComplete {
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusOK)
			json.NewEncoder(w).Encode(HealthResponse{Status: StatusUp})
			return
		}

		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusServiceUnavailable)
		json.NewEncoder(w).Encode(HealthResponse{
			Status: StatusDown,
			Components: map[string]ComponentStatus{
				"startup": {Status: StatusDown, Message: "still initializing"},
			},
		})
	}
}

// WatchGRPCState monitors gRPC connection state changes and logs them.
func (c *Checker) WatchGRPCState(ctx context.Context) {
	c.mu.RLock()
	conn := c.grpcConn
	target := c.grpcTarget
	c.mu.RUnlock()

	if conn == nil {
		return
	}

	for {
		currentState := conn.GetState()
		if !conn.WaitForStateChange(ctx, currentState) {
			return
		}
		newState := conn.GetState()
		zap.L().Info("gRPC connection state changed",
			zap.String("target", target),
			zap.String("from", currentState.String()),
			zap.String("to", newState.String()),
		)

		select {
		case <-ctx.Done():
			return
		case <-time.After(100 * time.Millisecond):
		}
	}
}

files.internal/helper/helper.go:
package helper

import (
	"context"
	"esb-go-libs/db"
	kafka "esb-go-libs/kafka"
	esblog "esb-go-libs/log"
	util "esb-go-libs/util"
	"fec_pool_service/config"

	"go.uber.org/fx"
	"go.uber.org/zap"
)

func NewKafkaSinkProvider(lc fx.Lifecycle, cfg *config.Config) (*kafka.Sink, error) {
	if len(cfg.LogCfg.KafkaBroker) == 0 {
		return nil, nil
	}

	kafkaConfig := kafka.Config{
		Brokers:       cfg.LogCfg.KafkaBroker,
		Topic:         "ESB_Transaction",
		User:          cfg.LogCfg.KafkaUser,
		Password:      cfg.LogCfg.KafkaPassword,
		FallbackPath:  "failed_kafka_logs.log",
		FlushFreq:     cfg.LogCfg.FlushSeq,
		BatchSize:     cfg.LogCfg.BatchSize,
		UseSync:       cfg.LogCfg.UseSync,
		QueueCapacity: 1000,
	}

	sink, err := kafka.NewSink(kafkaConfig)
	if err != nil {
		return nil, err
	}
	lc.Append(fx.Hook{
		OnStop: func(ctx context.Context) error {
			return sink.Close()
		},
	})

	return sink, nil
}
func NewLoggerProvider(cfg *config.Config, kafkaSink *kafka.Sink) *zap.Logger {
	logConfig := esblog.LogConfig{
		AppName:  cfg.App,
		LogLevel: cfg.LogCfg.LogLevel,
		FileCfg:  &esblog.FileConfig{Folder: cfg.LogCfg.Folder, FileName: cfg.LogCfg.FileName, MaxSize: cfg.LogCfg.LogSize, MaxBackup: cfg.LogCfg.Backup, MaxAge: cfg.LogCfg.MaxAge},
		Env:      cfg.Environment,
	}

	return esblog.NewEsbZapLogger(logConfig, kafkaSink)
}

func Provide() fx.Option {
	return fx.Provide(
		NewKafkaSinkProvider,
		fx.Annotate(
			func(cfg *config.Config) db.DBHelper {
				return db.NewOracleDBHelper(db.OracleConfig{Port: cfg.OracleDB.Port, Host: cfg.OracleDB.Host, Username: cfg.OracleDB.Username, Password: cfg.OracleDB.Password, ServiceName: cfg.OracleDB.ServiceName})
			},
		),
		util.NewPbConverter,
		NewLoggerProvider,
	)
}

