package repository

import (
	"context"
	"database/sql"
	"database/sql/driver"
	dbLib "esb-go-libs/db"
	"fmt"
	"reflect"
	"time"

	"fec_pool_service/config"
	"fec_pool_service/internal/dto"
	"fec_pool_service/internal/repository/model"

	go_ora "github.com/sijms/go-ora/v2"
	"go.elastic.co/apm/v2"
	"go.uber.org/zap"
)

type (
	IFecPoolServiceRepository interface {
		ExecuteQuery(ctx context.Context, transID string, query *model.Query) (result []map[string]interface{}, err error)
		ExecuteProcedure(ctx context.Context, transID, procedureCall string, args []interface{}, outIndices, outCursorIndices []int) ([]dto.CursorResult, []interface{}, error)
		ExecuteDML(ctx context.Context, transID string, query *model.Query) (int64, error)
	}

	FecPoolServiceRepositoryImpl struct {
		dbHelper dbLib.DBHelper
		cfg      *config.Config
	}
)

func NewPoolServiceRepository(
	DBHelper dbLib.DBHelper,
	cfg *config.Config) IFecPoolServiceRepository {
	db := DBHelper.Open()
	db.SetMaxOpenConns(cfg.OracleDB.MaxConn)
	db.SetMaxIdleConns(cfg.OracleDB.MinConn)
	db.SetConnMaxLifetime(time.Duration(cfg.OracleDB.ConnLT) * time.Minute)
	return &FecPoolServiceRepositoryImpl{dbHelper: DBHelper, cfg: cfg}
}

func (i *FecPoolServiceRepositoryImpl) ExecuteQuery(ctx context.Context, transID string, query *model.Query) ([]map[string]interface{}, error) {
	span, ctx := apm.StartSpan(ctx, "fec-pool-service.repo.ExecuteQuery", "fec-pool-service")
	defer span.End()

	span.Context.SetLabel("TransID", transID)
	db := i.dbHelper.Open()
	conn, err := db.Conn(ctx)
	if err != nil {
		zap.L().Error("Failed to get connection pool", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
		return nil, err
	}
	defer conn.Close()
	rows, err := conn.QueryContext(ctx, query.QueryStr, query.Args...)

	if err != nil {
		errOv := dbLib.NormalizeSQLError(err)
		if errOv == driver.ErrBadConn {
			zap.L().Error("Failed to execute query with bad connection, waiting for reset pool connection ...", zap.String("TransID", transID),
				zap.String("QueryStr", query.QueryStr), zap.String("ErrMsg", err.Error()))
			//i.dbHelper.ResetConnetionPool()

		} else {
			zap.L().Error("Failed to execute query", zap.String("TransID", transID), zap.String("QueryStr", query.QueryStr), zap.String("ErrMsg", err.Error()))
		}
		return nil, err
	}
	defer rows.Close()

	columns, err := rows.Columns()
	if err != nil {
		zap.L().Error("Failed to collect columns", zap.String("TransID", transID), zap.String("QueryStr", query.QueryStr), zap.String("ErrMsg", err.Error()))
		return nil, err
	}

	var queryResult []map[string]interface{}
	for rows.Next() {
		values := make([]interface{}, len(columns))
		pointers := make([]interface{}, len(columns))
		for i := range values {
			pointers[i] = &values[i]
		}

		if err := rows.Scan(pointers...); err != nil {
			zap.L().Error("Failed to scan data rows", zap.String("TransID", transID), zap.String("QueryStr", query.QueryStr), zap.String("ErrMsg", err.Error()))
			return nil, err
		}

		rowData := make(map[string]interface{}, len(columns))
		for i, col := range columns {
			if values[i] != nil {
				rowData[col] = values[i]
			} else {
				rowData[col] = ""
			}
		}
		queryResult = append(queryResult, rowData)
	}

	if err = rows.Err(); err != nil {
		zap.L().Error("Failed to iterate data", zap.String("TransID", transID), zap.String("QueryStr", query.QueryStr), zap.String("ErrMsg", err.Error()))
		return nil, err
	}
	if len(queryResult) == 0 {
		return queryResult, sql.ErrNoRows
	}
	return queryResult, nil
}

func (i *FecPoolServiceRepositoryImpl) ExecuteProcedure(ctx context.Context, transID, procedureCall string, args []interface{}, outIndices, outCursorIndices []int) (cursors []dto.CursorResult, outParams []interface{}, err error) {
	var (
		goOraOutType = reflect.TypeOf(go_ora.Out{})
		sqlOutType   = reflect.TypeOf(sql.Out{})
		timePtrType  = reflect.TypeOf((*time.Time)(nil))
	)
	span, ctx := apm.StartSpan(ctx, "fec-pool-service.repo.ExecuteProcedure", "fec-pool-service")
	defer span.End()

	span.Context.SetLabel("TransID", transID)
	defer func() {
		if r := recover(); r != nil {
			zap.L().Error("Recovered from panic ExecuteProcedure",
				zap.String("TransID", transID),
				zap.String("ErrMsg", fmt.Sprintf("%v", r)),
				zap.Stack("stacktrace"),
			)
			cursors = nil
			outParams = nil
			err = fmt.Errorf("panic recovered in ExecuteProcedure: %v", r)
		}
	}()

	db := i.dbHelper.Open()
	zap.L().Debug("Connection pool stats", zap.Int("OpenConns", db.Stats().OpenConnections), zap.Int("MaxOpenConns", db.Stats().MaxOpenConnections), zap.String("TransID", transID))

	conn, err := db.Conn(ctx)
	if err != nil {
		zap.L().Error("Failed to get connection pool", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
		return nil, nil, err
	}
	defer conn.Close()
	_, err = conn.ExecContext(ctx, procedureCall, args...)
	if err != nil {
		errOv := dbLib.NormalizeSQLError(err)
		if errOv == driver.ErrBadConn {
			zap.L().Error("Failed to execute procedure with bad connection, waiting for reset pool connection ...", zap.String("TransID", transID),
				zap.String("QueryStr", procedureCall), zap.String("ErrMSg", err.Error()))
			//i.dbHelper.ResetConnetionPool()
		} else {
			zap.L().Error("Failed to execute procedure", zap.String("TransID", transID),
				zap.String("QueryStr", procedureCall), zap.String("ErrMSg", err.Error()))
		}
		return nil, nil, err
	}
	var (
		isDataFound bool = false
	)
	for _, idx := range outCursorIndices {
		outVal, ok := args[idx].(sql.Out)
		if !ok || outVal.Dest == nil {
			zap.L().Warn("Invalid out parameter for cursor", zap.String("TransID", transID), zap.Int("Index", idx))
			continue
		}

		refCursor, ok := outVal.Dest.(*go_ora.RefCursor)
		if !ok || refCursor == nil {
			zap.L().Warn("RefCursor is invalid", zap.String("TransID", transID), zap.Int("Index", idx), zap.Bool("Ok", ok))
			continue
		}

		// Driver chưa kịp gán connection cho cursor (procedure có thể đã raise ORA
		// nhưng bị nuốt bởi EXCEPTION WHEN OTHERS, hoặc chưa kịp OPEN ... FOR ...).
		// Bỏ qua để tránh nil pointer dereference khi gọi Query()/Close().
		if !isCursorReady(refCursor) {
			zap.L().Warn("RefCursor not initialized by driver, skipping",
				zap.String("TransID", transID),
				zap.String("QueryStr", procedureCall),
				zap.Int("Index", idx))
			continue
		}

		zap.L().Debug("RefCursor state", zap.Any("RefCursor", refCursor), zap.String("TransID", transID), zap.Int("Index", idx))

		cursorRows, hasData, procErr := i.processCursor(transID, procedureCall, refCursor)
		if procErr != nil {
			continue
		}
		if hasData {
			isDataFound = true
		}

		cursors = append(cursors, dto.CursorResult{
			Rows: cursorRows,
		})
	}
	if (len(outCursorIndices) > 0 && isDataFound) || len(outCursorIndices) == 0 {
		result := make([]interface{}, len(outIndices))

		for i, idx := range outIndices {
			pointerType := reflect.TypeOf(args[idx])
			if pointerType == sqlOutType {
				// sql.Out such as NUMBER,DATE ....
				outVal, ok := args[idx].(sql.Out)
				if !ok {
					result[i] = nil
					continue
				}
				valuesType := reflect.TypeOf(outVal.Dest)
				if valuesType == timePtrType {
					timeValue, timeOk := outVal.Dest.(*time.Time)
					if timeOk && timeValue != nil && timeValue.IsZero() {
						result[i] = ""
					} else {
						result[i] = outVal.Dest
					}
				} else if outVal.Dest != nil {
					result[i] = outVal.Dest
				} else {
					result[i] = nil
				}
			} else if pointerType == goOraOutType {
				// VARCHAR2
				outVal, ok := args[idx].(go_ora.Out)
				if ok && outVal.Dest != nil {
					result[i] = outVal.Dest
				} else {
					result[i] = nil
				}
			} else {
				//does not support others type
				result[i] = nil
			}
		}

		return cursors, result, nil
	} else {
		return cursors, nil, sql.ErrNoRows
	}

}
func (i *FecPoolServiceRepositoryImpl) ExecuteDML(ctx context.Context, transID string, query *model.Query) (int64, error) {
	span, ctx := apm.StartSpan(ctx, "fec-pool-service.repo.ExecuteDML", "fec-pool-service")
	defer span.End()

	span.Context.SetLabel("TransID", transID)
	db := i.dbHelper.Open()
	zap.L().Info("Executing DML query", zap.String("TransID", transID), zap.String("QueryStr", query.QueryStr), zap.Any("Args", query.Args))

	conn, err := db.Conn(ctx)
	if err != nil {
		zap.L().Error("Failed to get connection pool", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
		return 0, err
	}
	defer conn.Close()

	maxRetries := i.cfg.OracleDB.MaxRetries
	if maxRetries <= 0 {
		maxRetries = 3
	}

	var result sql.Result
	for attempt := 1; attempt <= maxRetries; attempt++ {
		var execErr error
		result, execErr = conn.ExecContext(ctx, query.QueryStr, query.Args...)
		if execErr != nil {
			errOv := dbLib.NormalizeSQLError(execErr)
			if errOv != driver.ErrBadConn {
				// Logic error from DB(constraint, syntax...) → does not retry
				zap.L().Error("DML execution failed (non-retryable)",
					zap.String("TransID", transID),
					zap.String("QueryStr", query.QueryStr),
					zap.String("ErrMsg", execErr.Error()))
				return 0, execErr
			}

			// Bad connection → close cũ, lấy mới
			if attempt == maxRetries {
				zap.L().Error("Failed to execute DML after max retries",
					zap.String("TransID", transID),
					zap.String("QueryStr", query.QueryStr),
					zap.String("ErrMsg", execErr.Error()))
				return 0, execErr
			}

			zap.L().Warn("Retrying DML query (bad connection)",
				zap.String("TransID", transID),
				zap.String("QueryStr", query.QueryStr),
				zap.Int("Attempt", attempt))

			conn.Close()
			time.Sleep(time.Millisecond * 100 * time.Duration(attempt))

			conn, err = db.Conn(ctx)
			if err != nil {
				zap.L().Error("Failed to get new connection for retry",
					zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
				return 0, err
			}
			continue
		}
		break
	}

	affectedRows, err := result.RowsAffected()
	if err != nil {
		zap.L().Error("Failed to get affected rows", zap.String("TransID", transID), zap.String("QueryStr", query.QueryStr), zap.Error(err))
		return 0, err
	}

	zap.L().Debug("DML query executed successfully", zap.String("TransID", transID), zap.String("QueryStr", query.QueryStr), zap.Int64("AffectedRows", affectedRows))

	return affectedRows, nil
}

// processCursor handles a single RefCursor: queries rows and ensures the cursor is closed
// via defer when this function returns, avoiding defer-in-loop and double-close issues.
func (i *FecPoolServiceRepositoryImpl) processCursor(
	transID, procedureCall string,
	refCursor *go_ora.RefCursor,
) (cursorRows []map[string]interface{}, hasData bool, err error) {
	// Cache panic of Query() and this function.
	defer func() {
		if r := recover(); r != nil {
			zap.L().Error("Recovered from panic in processCursor",
				zap.String("TransID", transID),
				zap.String("QueryStr", procedureCall),
				zap.String("ErrMsg", fmt.Sprintf("%v", r)),
				zap.Stack("stacktrace"),
			)
			cursorRows = nil
			hasData = false
			err = fmt.Errorf("panic recovered in processCursor: %v", r)
		}
	}()

	// cache panic for Close() to prevent create new panic
	// when unwind (happening when cursor.connection stil is nil).
	defer func() {
		defer func() {
			if r := recover(); r != nil {
				zap.L().Error("Recovered from panic on RefCursor.Close",
					zap.String("TransID", transID),
					zap.String("QueryStr", procedureCall),
					zap.String("ErrMsg", fmt.Sprintf("%v", r)),
				)
			}
		}()
		if refCursor != nil && isCursorReady(refCursor) {
			if cerr := refCursor.Close(); cerr != nil {
				zap.L().Error("Failed to close RefCursor",
					zap.String("TransID", transID),
					zap.String("QueryStr", procedureCall),
					zap.String("ErrMsg", cerr.Error()))
			}
		}
	}()

	rows, qerr := refCursor.Query()
	if qerr != nil {
		zap.L().Error("Failed to query RefCursor",
			zap.String("TransID", transID),
			zap.String("QueryStr", procedureCall),
			zap.String("ErrMsg", qerr.Error()))
		return nil, false, qerr
	}

	if rows == nil {
		zap.L().Warn("No valid rows from RefCursor", zap.String("TransID", transID))
		return nil, false, nil
	}

	columns := rows.Columns()

	for rows.Next_() {
		hasData = true
		values := make([]interface{}, len(columns))
		pointers := make([]interface{}, len(columns))
		for j := range values {
			pointers[j] = &values[j]
		}

		if scanErr := rows.Scan(pointers...); scanErr != nil {
			zap.L().Error("Failed to scan data from cursor",
				zap.String("TransID", transID),
				zap.String("QueryStr", procedureCall),
				zap.String("ErrMsg", scanErr.Error()))
			rows.Close()
			continue
		}

		rowData := make(map[string]interface{}, len(columns))
		for j, col := range columns {
			if values[j] != nil {
				rowData[col] = values[j]
			} else {
				rowData[col] = ""
			}
		}
		cursorRows = append(cursorRows, rowData)
	}

	if cerr := rows.Close(); cerr != nil {
		zap.L().Error("Failed to close row data from cursor",
			zap.String("TransID", transID),
			zap.String("QueryStr", procedureCall),
			zap.String("ErrMsg", cerr.Error()))
	}

	return cursorRows, hasData, nil
}

// isCursorReady check cursor had been set connection yet
// If connection nil mean driver does not init cursor, the cursor is invalid and inaccessible
func isCursorReady(c *go_ora.RefCursor) bool {
	if c == nil {
		return false
	}
	defer func() { _ = recover() }()

	v := reflect.ValueOf(c).Elem()
	stmt := v.FieldByName("defaultStmt")
	if !stmt.IsValid() {
		return false
	}
	conn := stmt.FieldByName("connection")
	if !conn.IsValid() || conn.Kind() != reflect.Ptr {
		return false
	}
	return !conn.IsNil()
}

