package repository

import (
	"errors"
	"testing"

	go_ora "github.com/sijms/go-ora/v2"
)

// BenchmarkIsCursorReady_NilCursor đo chi phí của guard với input nil.
func BenchmarkIsCursorReady_NilCursor(b *testing.B) {
	var c *go_ora.RefCursor
	b.ReportAllocs()
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		_ = isCursorReady(c)
	}
}

// BenchmarkIsCursorReady_UninitCursor đo chi phí khi cursor non-nil
// nhưng connection chưa được driver gán (case panic ban đầu).
func BenchmarkIsCursorReady_UninitCursor(b *testing.B) {
	c := &go_ora.RefCursor{}
	b.ReportAllocs()
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		_ = isCursorReady(c)
	}
}

// BenchmarkDeferRecover_NoPanic mô phỏng overhead của 2 tầng
// defer+recover khi không có panic xảy ra (happy path).
func BenchmarkDeferRecover_NoPanic(b *testing.B) {
	b.ReportAllocs()
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		func() (err error) {
			defer func() {
				if r := recover(); r != nil {
					err = errors.New("outer recovered")
				}
			}()
			defer func() {
				defer func() {
					_ = recover()
				}()
				// mô phỏng Close() thành công, không panic
			}()
			// happy path
			_ = err
			return nil
		}()
	}
}

// BenchmarkDeferRecover_WithPanic đo chi phí khi panic thực sự xảy ra
// và được recover (case bất thường, ít gặp).
func BenchmarkDeferRecover_WithPanic(b *testing.B) {
	b.ReportAllocs()
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		func() (err error) {
			defer func() {
				if r := recover(); r != nil {
					err = errors.New("recovered")
				}
			}()
			panic("boom")
		}()
	}
}

// BenchmarkOldDeferOnly mô phỏng cấu trúc cũ: chỉ 1 defer Close, không có recover.
// Dùng để so sánh baseline với BenchmarkDeferRecover_NoPanic.
func BenchmarkOldDeferOnly(b *testing.B) {
	b.ReportAllocs()
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		func() {
			defer func() {
				// mô phỏng Close()
			}()
		}()
	}
}

