package repository

import (
	"strings"
	"testing"

	go_ora "github.com/sijms/go-ora/v2"
	"github.com/stretchr/testify/assert"
)

// ==================== isCursorReady ====================

func TestIsCursorReady_NilCursor(t *testing.T) {
	var c *go_ora.RefCursor
	assert.False(t, isCursorReady(c), "nil cursor must be reported as not ready")
}

func TestIsCursorReady_UninitializedCursor(t *testing.T) {
	// Cursor non-nil nhưng driver chưa gán connection
	// (case ORA bị nuốt bởi EXCEPTION WHEN OTHERS).
	c := &go_ora.RefCursor{}
	assert.False(t, isCursorReady(c), "cursor with nil connection must be reported as not ready")
}

// ==================== processCursor: panic safety ====================

func TestProcessCursor_NilCursor_NoPanic(t *testing.T) {
	repo := &FecPoolServiceRepositoryImpl{}

	assert.NotPanics(t, func() {
		rows, hasData, err := repo.processCursor("tx-nil", "BEGIN dummy; END;", nil)
		// Khi cursor nil, gọi Query() trên nil pointer -> panic -> defer recover trả error.
		assert.Error(t, err)
		assert.False(t, hasData)
		assert.Nil(t, rows)
	})
}

func TestProcessCursor_UninitializedCursor_NoPanic(t *testing.T) {
	repo := &FecPoolServiceRepositoryImpl{}
	cursor := &go_ora.RefCursor{}

	// Cursor non-nil nhưng connection nil -> Query() panic, defer recover bắt được,
	// Close() không được gọi (do isCursorReady=false), không có panic kép.
	assert.NotPanics(t, func() {
		rows, hasData, err := repo.processCursor("tx-uninit", "BEGIN dummy; END;", cursor)
		assert.Error(t, err)
		assert.Contains(t, err.Error(), "panic recovered in processCursor")
		assert.False(t, hasData)
		assert.Nil(t, rows)
	})
}

// ==================== ExecuteProcedure: outer recover ====================

// Verify rằng nếu có panic phát sinh từ processCursor, ExecuteProcedure vẫn
// trả về error sạch thay vì để panic thoát ra ngoài.
func TestProcessCursor_ErrorMessageContainsContext(t *testing.T) {
	repo := &FecPoolServiceRepositoryImpl{}
	cursor := &go_ora.RefCursor{}

	_, _, err := repo.processCursor("tx-ctx", "BEGIN test_proc(:c); END;", cursor)
	if assert.Error(t, err) {
		// Error phải có prefix nhận biết được để alert/log có context.
		assert.True(t, strings.HasPrefix(err.Error(), "panic recovered in processCursor"),
			"unexpected error message: %s", err.Error())
	}
}

