package usecase

import (
	"context"
	"database/sql"
	"fec_pool_service/internal/dto"
	"fec_pool_service/internal/repository"
	"fec_pool_service/internal/repository/model"
	"fec_pool_service/internal/util"
	"fmt"
	"reflect"
	"regexp"
	"strconv"
	"strings"
	"time"

	goora "github.com/sijms/go-ora/v2"
	"go.elastic.co/apm/v2"
	"go.uber.org/zap"
)

const (
	DataTypeNumber       = "NUMBER"
	DataTypeVarchar2     = "VARCHAR2"
	DataTypeDate         = "DATE"
	DataTypeFloat        = "FLOAT"
	DataTypeTimestamp    = "TIMESTAMP"
	DataTypeCursor       = "CURSOR"
	DataTypeClob         = "CLOB"
	DataTypeBlob         = "BLOB"
	DataTypeRaw          = "RAW"
	DataTypeLong         = "LONG"
	DataTypeChar         = "CHAR"
	DataTypeNChar        = "NCHAR"
	DataTypeNVarchar2    = "NVARCHAR2"
	DataTypeBinaryDouble = "BINARY_DOUBLE"
)

const (
	DateFormat        = "2006-01-02"
	TimestampFormat   = "2006-01-02 15:04:05.999999999"
	maxLengthVarchar2 = 4000
)

type (
	IFecPoolServiceUseCase interface {
		ExecuteQuery(ctx context.Context, req *dto.ExecuteQueryRequestDTO, transID string) *dto.ExecuteQueryResponseDTO
	}

	FecPoolServiceUseCaseImpl struct {
		poolRepository repository.IFecPoolServiceRepository
		querySecurity  util.QuerySecurityConfig
	}
)

func NewFecPoolServiceUseCase(
	poolRepository repository.IFecPoolServiceRepository,
	querySecurity util.QuerySecurityConfig,
) IFecPoolServiceUseCase {
	return &FecPoolServiceUseCaseImpl{
		poolRepository: poolRepository,
		querySecurity:  querySecurity,
	}
}

type preparedRepoArgs struct {
	TransformedQuery string
	Args             []any
	OutIndices       []int
	OutCursorIndices []int
	NameToIndex      map[string]int
}

type paramDirection string

const (
	paramDirIn    paramDirection = "IN"
	paramDirInOut paramDirection = "INOUT"
	paramDirOut   paramDirection = "OUT"
)

type paramInfo struct {
	Param     dto.QueryParamsDTO
	Direction paramDirection
}

func (u *FecPoolServiceUseCaseImpl) ExecuteQuery(
	ctx context.Context,
	req *dto.ExecuteQueryRequestDTO,
	transID string,
) *dto.ExecuteQueryResponseDTO {
	span, ctx := apm.StartSpan(ctx, "fec-pool-service.usecase.ExecuteQuery", "fec-pool-service")
	defer span.End()

	span.Context.SetLabel("TransID", req.Sys.TransID)

	// Validate query against security rules
	if err := util.ValidateQuery(req.QueryString, u.querySecurity); err != nil {
		zap.L().Error("Query validation failed", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
		return &dto.ExecuteQueryResponseDTO{Error: fmt.Errorf("query rejected: %w", err)}
	}

	// Prepare parameters
	repoArgs, err := prepareParameters(req, transID)
	if err != nil {
		zap.L().Error("Parameter preparation failed", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
		return &dto.ExecuteQueryResponseDTO{Error: err}
	}

	isProcedure := len(req.OutputParameters) > 0 || len(req.InputOutputParameters) > 0
	isDML := isDMLStatement(req.QueryString)

	switch {
	case isProcedure:
		return u.executeProcedure(ctx, transID, repoArgs)
	case isDML:
		return u.executeDML(ctx, transID, repoArgs)
	default:
		return u.executeSelect(ctx, transID, repoArgs)
	}
}

func prepareParameters(req *dto.ExecuteQueryRequestDTO, transID string) (*preparedRepoArgs, error) {

	protectedQuery, literals := util.ProtectLiterals(req.QueryString)

	// Get all param as position in query string
	re := regexp.MustCompile(`:\w+`)
	matches := re.FindAllString(protectedQuery, -1)

	// name of param must be unique
	orderedUniqueNames := make([]string, 0)
	seen := make(map[string]bool)
	for _, match := range matches {
		name := strings.TrimPrefix(match, ":")
		if !seen[name] {
			seen[name] = true
			orderedUniqueNames = append(orderedUniqueNames, name)
		}
	}

	if len(orderedUniqueNames) == 0 {
		return &preparedRepoArgs{TransformedQuery: req.QueryString, Args: make([]any, 0)}, nil
	}

	// create new querystring, replace name with position
	transformedProtectedQuery := protectedQuery
	nameToIndexMap := make(map[string]int)
	for i, name := range orderedUniqueNames {
		index := i
		position := i + 1
		nameToIndexMap[name] = index
		replacement := ":" + strconv.Itoa(position)
		pattern := ":" + regexp.QuoteMeta(name) + `\b`
		re := regexp.MustCompile(pattern)
		transformedProtectedQuery = re.ReplaceAllString(transformedProtectedQuery, replacement)
	}
	finalTransformedQuery := util.RestoreLiterals(transformedProtectedQuery, literals)

	//create map of params to improve performance to search param and get value of it
	paramLookup := make(map[string]paramInfo)
	for _, p := range req.InputParameters {
		paramLookup[p.Name] = paramInfo{Param: p, Direction: paramDirIn}
	}
	for _, p := range req.InputOutputParameters {
		paramLookup[p.Name] = paramInfo{Param: p, Direction: paramDirInOut}
	}
	for _, p := range req.OutputParameters {
		paramLookup[p.Name] = paramInfo{Param: p, Direction: paramDirOut}
	}

	repoArgs := &preparedRepoArgs{
		TransformedQuery: finalTransformedQuery,
		//TransformedQuery: finalTransformedQuery,
		Args:             make([]any, len(orderedUniqueNames)),
		OutIndices:       make([]int, 0),
		OutCursorIndices: make([]int, 0),
		NameToIndex:      nameToIndexMap,
	}

	for _, name := range orderedUniqueNames {
		paramInfo, ok := paramLookup[name]
		if !ok {
			zap.L().Error("Invalid parameters", zap.String("TransID", transID), zap.String("ErrMsg", fmt.Sprintf("Parameter '%s' found in query but not provided in request", name)))
			return nil, fmt.Errorf("parameter '%s' found in query but not provided in request", name)
		}

		index := nameToIndexMap[name]
		paramDTO := paramInfo.Param

		switch paramInfo.Direction {
		case paramDirIn:
			val, err := convertInputParam(paramDTO, transID)
			if err != nil {
				return nil, err
			}
			repoArgs.Args[index] = val
		case paramDirInOut:
			dest, err := convertInOutParam(paramDTO, transID)
			if err != nil {
				return nil, err
			}
			switch paramDTO.DataType {
			case DataTypeVarchar2, DataTypeChar, DataTypeNChar, DataTypeNVarchar2, DataTypeClob, DataTypeLong:
				repoArgs.Args[index] = goora.Out{Dest: dest, Size: maxLengthVarchar2, In: true}
			default:
				repoArgs.Args[index] = sql.Out{Dest: dest, In: true}
			}
			repoArgs.OutIndices = append(repoArgs.OutIndices, index)
		case paramDirOut:
			dest, err := convertOutParam(paramDTO)
			if err != nil {
				return nil, err
			}
			switch paramDTO.DataType {
			case DataTypeVarchar2, DataTypeChar, DataTypeNChar, DataTypeNVarchar2, DataTypeClob, DataTypeLong:
				repoArgs.Args[index] = goora.Out{Dest: dest, Size: maxLengthVarchar2}
			default:
				repoArgs.Args[index] = sql.Out{Dest: dest}
			}
			if paramDTO.DataType == DataTypeCursor {
				repoArgs.OutCursorIndices = append(repoArgs.OutCursorIndices, index)
			} else {
				repoArgs.OutIndices = append(repoArgs.OutIndices, index)
			}
		}

	}
	return repoArgs, nil
}

func convertInputParam(param dto.QueryParamsDTO, transID string) (any, error) {
	switch param.DataType {
	case DataTypeNumber:
		num, err := strconv.ParseInt(param.Value, 10, 64)
		if err != nil {
			zap.L().Error("Invalid number input parameter", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
			return nil, err
		}
		return num, nil
	case DataTypeVarchar2, DataTypeChar, DataTypeNChar, DataTypeNVarchar2, DataTypeLong:
		if err := util.ValidateParamValue(param.Value); err != nil {
			zap.L().Error("Parameter value validation failed", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
			return nil, err
		}
		return param.Value, nil
	case DataTypeDate:
		t, err := time.Parse(DateFormat, param.Value)
		if err != nil {
			zap.L().Error("Invalid date input parameter", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
			return nil, err
		}
		return t, nil
	case DataTypeTimestamp:
		t, err := time.Parse(TimestampFormat, param.Value)
		if err != nil {
			zap.L().Error("Invalid timestamp input parameter", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
			return nil, err
		}
		return t, nil
	case DataTypeFloat, DataTypeBinaryDouble:
		f, err := strconv.ParseFloat(param.Value, 64)
		if err != nil {
			zap.L().Error("Invalid float/binary_double input parameter", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
			return nil, err
		}
		return f, nil
	case DataTypeRaw, DataTypeBlob:
		return []byte(param.Value), nil
	case DataTypeClob:
		if err := util.ValidateParamValue(param.Value); err != nil {
			zap.L().Error("Parameter value validation failed", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
			return nil, err
		}
		return goora.Clob{
			String: param.Value,
			Valid:  true,
		}, nil
	default:
		return param.Value, nil
	}
}

func convertInOutParam(param dto.QueryParamsDTO, transID string) (any, error) {
	switch param.DataType {
	case DataTypeNumber:
		num, err := strconv.ParseInt(param.Value, 10, 64)
		if err != nil {
			zap.L().Error("Invalid number inout parameter", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
			return nil, err
		}
		return &num, nil
	case DataTypeVarchar2, DataTypeChar, DataTypeNChar, DataTypeNVarchar2, DataTypeClob, DataTypeLong:
		dest := param.Value
		return &dest, nil
	case DataTypeDate:
		t, err := time.Parse(DateFormat, param.Value)
		if err != nil {
			zap.L().Error("Invalid date inout parameter", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
			return nil, err
		}
		return &t, nil
	case DataTypeTimestamp:
		t, err := time.Parse(TimestampFormat, param.Value)
		if err != nil {
			zap.L().Error("Invalid timestamp inout parameter", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
			return nil, err
		}
		return &t, nil
	case DataTypeFloat, DataTypeBinaryDouble:
		f, err := strconv.ParseFloat(param.Value, 64)
		if err != nil {
			zap.L().Error("Invalid float/binary_double inout parameter", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
			return nil, err
		}
		return &f, nil
	case DataTypeRaw, DataTypeBlob:
		value := []byte(param.Value)
		return &value, nil
	case DataTypeCursor:
		return nil, fmt.Errorf("%s - InOutParameters does not support cursor type", transID)
	default:
		dest := param.Value
		return &dest, nil
	}
}

func convertOutParam(param dto.QueryParamsDTO) (any, error) {
	switch param.DataType {
	case DataTypeNumber:
		var num int64
		return &num, nil
	case DataTypeVarchar2, DataTypeChar, DataTypeNChar, DataTypeNVarchar2, DataTypeClob, DataTypeLong:
		var value string
		return &value, nil
	case DataTypeDate, DataTypeTimestamp:
		var t time.Time
		return &t, nil
	case DataTypeFloat, DataTypeBinaryDouble:
		var f float64
		return &f, nil
	case DataTypeRaw, DataTypeBlob:
		var value []byte
		return &value, nil
	case DataTypeCursor:
		var cursor goora.RefCursor
		return &cursor, nil
	default:
		var value string
		return &value, nil
	}
}

func isDMLStatement(query string) bool {
	query = strings.TrimSpace(strings.ToUpper(query))
	dmlPrefixes := []string{"INSERT ", "UPDATE ", "MERGE ", "DELETE "}
	for _, prefix := range dmlPrefixes {
		if strings.HasPrefix(query, prefix) {
			return true
		}
	}
	return false
}

func (u *FecPoolServiceUseCaseImpl) executeProcedure(
	ctx context.Context,
	transID string,
	repoArgs *preparedRepoArgs,
) *dto.ExecuteQueryResponseDTO {
	span, ctx := apm.StartSpan(ctx, "fec-pool-service.usecase.executeProcedure", "fec-pool-service")
	defer span.End()

	span.Context.SetLabel("TransID", transID)

	cursors, outParams, err := u.poolRepository.ExecuteProcedure(ctx, transID, repoArgs.TransformedQuery, repoArgs.Args, repoArgs.OutIndices, repoArgs.OutCursorIndices)
	if err != nil {
		if err != sql.ErrNoRows {
			zap.L().Error("Repository procedure execution failed", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
		}
		return &dto.ExecuteQueryResponseDTO{Error: err}
	}

	outParamMap := make(map[string]any)

	indexToNameMap := make(map[int]string)
	for name, index := range repoArgs.NameToIndex {
		indexToNameMap[index] = name
	}

	outCounter := 0
	for _, idx := range repoArgs.OutIndices {
		if outCounter < len(outParams) {
			paramName := indexToNameMap[idx]
			val := outParams[outCounter]
			if val == nil {
				outParamMap[paramName] = nil
			} else {
				rv := reflect.ValueOf(val)
				if rv.Kind() == reflect.Ptr {
					if rv.IsNil() {
						outParamMap[paramName] = nil
					} else {
						outParamMap[paramName] = rv.Elem().Interface()
					}
				} else {
					outParamMap[paramName] = val
				}
			}
			outCounter++
		}
	}

	cursorCounter := 0
	for _, idx := range repoArgs.OutCursorIndices {
		if cursorCounter < len(cursors) {
			paramName := indexToNameMap[idx]
			outParamMap[paramName] = cursors[cursorCounter]
			cursorCounter++
		}
	}

	zap.L().Debug("Procedure executed successfully", zap.String("TransID", transID))
	return &dto.ExecuteQueryResponseDTO{
		OutParams: outParamMap,
	}
}

func (u *FecPoolServiceUseCaseImpl) executeDML(
	ctx context.Context, transID string, repoArgs *preparedRepoArgs,
) *dto.ExecuteQueryResponseDTO {
	span, ctx := apm.StartSpan(ctx, "fec-pool-service.usecase.executeDML", "fec-pool-service")
	defer span.End()

	span.Context.SetLabel("TransID", transID)
	affectedRows, err := u.poolRepository.ExecuteDML(ctx, transID, &model.Query{
		QueryStr: repoArgs.TransformedQuery,
		Args:     repoArgs.Args,
	})
	if err != nil {
		zap.L().Error("DML execution failed", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
		return &dto.ExecuteQueryResponseDTO{Error: err}
	}

	zap.L().Debug("DML executed successfully",
		zap.String("TransID", transID),
		zap.Int64("affectedRows", affectedRows))
	return &dto.ExecuteQueryResponseDTO{
		OutParams: map[string]any{
			"affected_rows": affectedRows,
		},
	}
}

func (u *FecPoolServiceUseCaseImpl) executeSelect(
	ctx context.Context, transID string, repoArgs *preparedRepoArgs,
) *dto.ExecuteQueryResponseDTO {
	span, ctx := apm.StartSpan(ctx, "fec-pool-service.usecase.executeSelect", "fec-pool-service")
	defer span.End()

	span.Context.SetLabel("TransID", transID)
	query := &model.Query{
		QueryStr: repoArgs.TransformedQuery,
		Args:     repoArgs.Args,
	}
	results, err := u.poolRepository.ExecuteQuery(ctx, transID, query)
	if err != nil {
		if err != sql.ErrNoRows {
			zap.L().Error("Query execution failed", zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
		}
		return &dto.ExecuteQueryResponseDTO{Error: err}
	}

	outParamMap := make(map[string]any)
	if len(results) > 0 {
		outParamMap["result"] = dto.CursorResult{Rows: results}
	}

	zap.L().Debug("Query executed successfully",
		zap.String("TransID", transID),
		zap.Int("resultRows", len(results)))
	return &dto.ExecuteQueryResponseDTO{
		OutParams: outParamMap,
	}
}

