files.internal/util/query_validator.go:
package util

import (
	"fmt"
	"regexp"
	"strings"
)

// QuerySecurityConfig holds the validation rules for SQL queries.
type QuerySecurityConfig struct {
	AllowedPrefixes     []string
	BlockedKeywords     []string
	AllowMultiStatement bool
}

var defaultAllowedPrefixes = []string{
	"SELECT", "INSERT", "UPDATE", "DELETE", "MERGE", "BEGIN", "CALL", "DECLARE",
}

var defaultBlockedKeywords = []string{
	"DROP", "TRUNCATE", "ALTER", "CREATE", "GRANT", "REVOKE", "PURGE",
}

// defaultBlockedKeywordRegexes are pre-compiled regex for default blocked keywords.
var defaultBlockedKeywordRegexes = func() []compiledBlockedFunc {
	result := make([]compiledBlockedFunc, len(defaultBlockedKeywords))
	for i, kw := range defaultBlockedKeywords {
		result[i] = compiledBlockedFunc{
			name: kw,
			re:   regexp.MustCompile(`\b` + regexp.QuoteMeta(kw) + `\b`),
		}
	}
	return result
}()

// blockedFunctionRegexes contains pre-compiled regex patterns for Oracle functions
// that can be exploited for XXE, SSRF, or remote code execution attacks.
var blockedFunctionRegexes = func() []compiledBlockedFunc {
	functions := []string{
		"EXTRACTVALUE",
		"XMLTYPE",
		"XMLPARSE",
		"XMLSERIALIZE",
		"XMLELEMENT",
		"XMLFOREST",
		"XMLROOT",
		"XMLAGG",
		"UPDATEXML",
		"XMLQUERY",
		"XMLTABLE",
		"HTTPURITYPE",
		"DBMS_XMLPARSER",
		"UTL_HTTP",
		"UTL_INADDR",
		"UTL_FILE",
		"DBMS_LDAP",
	}
	result := make([]compiledBlockedFunc, len(functions))
	for i, fn := range functions {
		result[i] = compiledBlockedFunc{
			name: fn,
			re:   regexp.MustCompile(`\b` + regexp.QuoteMeta(fn) + `\b`),
		}
	}
	return result
}()

type compiledBlockedFunc struct {
	name string
	re   *regexp.Regexp
}

// blockedPatterns detects dangerous patterns like DOCTYPE/ENTITY declarations
// that could enable XXE attacks even when passed as string literals.
var blockedPatterns = []*regexp.Regexp{
	regexp.MustCompile(`(?i)<!DOCTYPE`),
	regexp.MustCompile(`(?i)<!ENTITY`),
	regexp.MustCompile(`(?i)SYSTEM\s+["']https?://`),
	regexp.MustCompile(`(?i)PUBLIC\s+["']`),
}

// ValidateQuery checks the query string against security rules.
// It operates on the "protected" version (string literals replaced by placeholders)
// so that content inside quotes cannot trick the validator.
func ValidateQuery(rawQuery string, cfg QuerySecurityConfig) error {
	if strings.TrimSpace(rawQuery) == "" {
		return fmt.Errorf("query string must not be empty")
	}

	// Work on a version with string literals stripped out
	protectedQuery, _ := ProtectLiterals(rawQuery)
	normalized := strings.TrimSpace(strings.ToUpper(protectedQuery))

	// 1. Check allowed prefixes
	allowedPrefixes := cfg.AllowedPrefixes
	if len(allowedPrefixes) == 0 {
		allowedPrefixes = defaultAllowedPrefixes
	}
	prefixOK := false
	for _, prefix := range allowedPrefixes {
		if strings.HasPrefix(normalized, strings.ToUpper(prefix)) {
			prefixOK = true
			break
		}
	}
	if !prefixOK {
		return fmt.Errorf("query prefix not allowed. Allowed: %v", allowedPrefixes)
	}

	// 2. Check blocked keywords (as whole words in the protected query)
	if len(cfg.BlockedKeywords) == 0 {
		// Use pre-compiled regexes for default blocked keywords
		for _, bk := range defaultBlockedKeywordRegexes {
			if bk.re.MatchString(normalized) {
				return fmt.Errorf("query contains blocked keyword: %s", bk.name)
			}
		}
	} else {
		for _, keyword := range cfg.BlockedKeywords {
			pattern := `\b` + regexp.QuoteMeta(strings.ToUpper(keyword)) + `\b`
			re := regexp.MustCompile(pattern)
			if re.MatchString(normalized) {
				return fmt.Errorf("query contains blocked keyword: %s", keyword)
			}
		}
	}

	// 3. Check blocked Oracle functions (XXE/SSRF vectors)
	for _, bf := range blockedFunctionRegexes {
		if bf.re.MatchString(normalized) {
			return fmt.Errorf("query contains blocked function: %s", bf.name)
		}
	}

	// 4. Check dangerous patterns in the RAW query (including inside string literals)
	// This catches XXE payloads hidden inside Oracle string literals.
	rawUpper := strings.ToUpper(rawQuery)
	for _, pat := range blockedPatterns {
		if pat.MatchString(rawUpper) {
			return fmt.Errorf("query contains dangerous pattern (possible XXE/SSRF attack)")
		}
	}

	// 5. Check multi-statement (semicolons outside string literals)
	if !cfg.AllowMultiStatement {
		if err := validateSemicolons(normalized); err != nil {
			return err
		}
	}

	return nil
}

// ValidateParamValue checks a string parameter value for dangerous patterns
// that could enable XXE or SSRF attacks when processed by Oracle XML functions.
func ValidateParamValue(value string) error {
	upper := strings.ToUpper(value)
	for _, pat := range blockedPatterns {
		if pat.MatchString(upper) {
			return fmt.Errorf("parameter value contains dangerous pattern (possible XXE/SSRF attack)")
		}
	}
	return nil
}

// blockPrefixes are PL/SQL constructs that legitimately need semicolons inside.
var blockPrefixes = []string{"BEGIN", "CALL", "DECLARE"}

// validateSemicolons applies different rules based on query type:
//   - Block statements (BEGIN, CALL, DECLARE): semicolons allowed freely inside,
//     but nothing meaningful may appear after the final closing semicolon.
//   - Simple statements (SELECT, INSERT, ...): only a single trailing semicolon allowed.
func validateSemicolons(normalized string) error {
	isBlock := false
	for _, bp := range blockPrefixes {
		if strings.HasPrefix(normalized, bp) {
			isBlock = true
			break
		}
	}

	trimmed := strings.TrimSpace(normalized)

	if isBlock {
		// For PL/SQL blocks, allow semicolons inside but reject trailing content
		// after the last ';'. e.g. "BEGIN proc(:1); END; DROP TABLE x" → reject.
		lastSemi := strings.LastIndex(trimmed, ";")
		if lastSemi >= 0 {
			afterLast := strings.TrimSpace(trimmed[lastSemi+1:])
			if afterLast != "" {
				return fmt.Errorf("unexpected content after final semicolon in block statement")
			}
		}
	} else {
		// For simple statements, strip one trailing ';' then reject any remaining ';'
		withoutTrailing := strings.TrimRight(trimmed, "; \t\n\r")
		if strings.Contains(withoutTrailing, ";") {
			return fmt.Errorf("multi-statement queries are not allowed")
		}
	}

	return nil
}

files.internal/util/query_validator_test.go:
package util

import (
	"strings"
	"testing"
)

// defaultCfg uses zero-value slices so ValidateQuery falls back to defaults.
var defaultCfg = QuerySecurityConfig{}

func TestValidateQuery_EmptyQuery(t *testing.T) {
	for _, q := range []string{"", "   ", "\t\n"} {
		if err := ValidateQuery(q, defaultCfg); err == nil {
			t.Errorf("expected error for empty query %q", q)
		}
	}
}

// --- Allowed prefix tests ---

func TestValidateQuery_AllowedPrefixes(t *testing.T) {
	cases := []struct {
		name  string
		query string
		ok    bool
	}{
		{"SELECT", "SELECT * FROM employees", true},
		{"select lowercase", "select * from employees", true},
		{"INSERT", "INSERT INTO employees (id) VALUES (1)", true},
		{"UPDATE", "UPDATE employees SET name = 'John' WHERE id = 1", true},
		{"DELETE", "DELETE FROM employees WHERE id = 1", true},
		{"MERGE", "MERGE INTO target USING source ON (target.id = source.id) WHEN MATCHED THEN UPDATE SET name = source.name", true},
		{"BEGIN", "BEGIN my_proc(:1); END;", true},
		{"CALL", "CALL my_proc(:1);", true},
		{"DECLARE", "DECLARE v NUMBER; BEGIN v := 1; END;", true},
		{"DROP rejected", "DROP TABLE employees", false},
		{"TRUNCATE rejected", "TRUNCATE TABLE employees", false},
		{"ALTER rejected", "ALTER TABLE employees ADD col NUMBER", false},
		{"CREATE rejected", "CREATE TABLE test (id NUMBER)", false},
		{"random text", "HELLO WORLD", false},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			err := ValidateQuery(tc.query, defaultCfg)
			if tc.ok && err != nil {
				t.Errorf("expected OK but got error: %v", err)
			}
			if !tc.ok && err == nil {
				t.Errorf("expected error but got nil for query: %s", tc.query)
			}
		})
	}
}

func TestValidateQuery_CustomAllowedPrefixes(t *testing.T) {
	cfg := QuerySecurityConfig{
		AllowedPrefixes: []string{"SELECT"},
	}
	if err := ValidateQuery("SELECT 1 FROM dual", cfg); err != nil {
		t.Errorf("SELECT should be allowed: %v", err)
	}
	if err := ValidateQuery("INSERT INTO t VALUES (1)", cfg); err == nil {
		t.Error("INSERT should be rejected with custom prefix list")
	}
}

// --- Blocked keyword tests ---

func TestValidateQuery_BlockedKeywords(t *testing.T) {
	cases := []struct {
		name  string
		query string
		ok    bool
	}{
		{"normal select", "SELECT id, name FROM employees WHERE id = :id", true},
		{"select with DROP in string literal", "SELECT * FROM employees WHERE name = 'DROP TABLE'", true},
		{"select containing DROP keyword", "SELECT * FROM employees; DROP TABLE employees", false},
		{"insert with TRUNCATE", "INSERT INTO log SELECT * FROM TRUNCATE", false},
		{"select with ALTER", "SELECT ALTER FROM dual", false},
		{"select with CREATE", "SELECT CREATE FROM dual", false},
		{"select with GRANT", "SELECT GRANT FROM dual", false},
		{"select with REVOKE", "SELECT REVOKE FROM dual", false},
		{"select with PURGE", "SELECT PURGE FROM dual", false},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			err := ValidateQuery(tc.query, defaultCfg)
			if tc.ok && err != nil {
				t.Errorf("expected OK but got error: %v", err)
			}
			if !tc.ok && err == nil {
				t.Errorf("expected error but got nil for query: %s", tc.query)
			}
		})
	}
}

func TestValidateQuery_BlockedKeywordInsideLiteral(t *testing.T) {
	// Blocked keywords inside string literals should NOT trigger rejection
	queries := []string{
		"SELECT * FROM employees WHERE name = 'DROP'",
		"SELECT * FROM employees WHERE desc = 'TRUNCATE this'",
		"INSERT INTO log (msg) VALUES ('ALTER TABLE done')",
		"UPDATE t SET note = 'CREATE new record' WHERE id = 1",
	}
	for _, q := range queries {
		if err := ValidateQuery(q, defaultCfg); err != nil {
			t.Errorf("blocked keyword inside literal should be OK: query=%s err=%v", q, err)
		}
	}
}

func TestValidateQuery_CustomBlockedKeywords(t *testing.T) {
	cfg := QuerySecurityConfig{
		BlockedKeywords: []string{"SHUTDOWN"},
	}
	// Default blocked keywords should not apply when custom list is provided
	if err := ValidateQuery("SELECT DROP FROM dual", cfg); err != nil {
		t.Errorf("DROP should not be blocked with custom list: %v", err)
	}
	if err := ValidateQuery("SELECT SHUTDOWN FROM dual", cfg); err == nil {
		t.Error("SHUTDOWN should be blocked with custom list")
	}
}

// --- Semicolon / multi-statement tests ---

func TestValidateQuery_SimpleStatementSemicolons(t *testing.T) {
	cases := []struct {
		name  string
		query string
		ok    bool
	}{
		{"no semicolon", "SELECT * FROM employees", true},
		{"trailing semicolon", "SELECT * FROM employees;", true},
		{"trailing semicolon with spaces", "SELECT * FROM employees ;  ", true},
		{"multi-statement SELECT;DELETE", "SELECT * FROM employees; DELETE FROM employees", false},
		{"multi-statement with newline", "INSERT INTO t VALUES(1);\nDELETE FROM t", false},
		{"UPDATE trailing ok", "UPDATE t SET x = 1 WHERE id = 2;", true},
		{"DELETE trailing ok", "DELETE FROM t WHERE id = 1;", true},
		{"MERGE trailing ok", "MERGE INTO t USING s ON (t.id=s.id) WHEN MATCHED THEN UPDATE SET t.x=s.x;", true},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			err := ValidateQuery(tc.query, defaultCfg)
			if tc.ok && err != nil {
				t.Errorf("expected OK but got error: %v", err)
			}
			if !tc.ok && err == nil {
				t.Errorf("expected error but got nil for query: %s", tc.query)
			}
		})
	}
}

func TestValidateQuery_BlockStatementSemicolons(t *testing.T) {
	cases := []struct {
		name  string
		query string
		ok    bool
	}{
		{"BEGIN END", "BEGIN my_proc(:1); END;", true},
		{"BEGIN multiple statements", "BEGIN proc1(:1); proc2(:2); END;", true},
		{"DECLARE block", "DECLARE v NUMBER; BEGIN v := 1; END;", true},
		{"CALL with semicolon", "CALL my_proc(:1);", true},
		{"CALL without semicolon", "CALL my_proc(:1)", true},
		{"BEGIN with trailing content", "BEGIN proc(:1); END; SELECT 1 FROM dual", false},
		{"DECLARE with trailing content", "DECLARE v NUMBER; BEGIN v:=1; END; INSERT INTO t VALUES(1)", false},
		{"CALL with trailing content", "CALL proc(:1); SELECT 1", false},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			err := ValidateQuery(tc.query, defaultCfg)
			if tc.ok && err != nil {
				t.Errorf("expected OK but got error: %v", err)
			}
			if !tc.ok && err == nil {
				t.Errorf("expected error but got nil for query: %s", tc.query)
			}
		})
	}
}

func TestValidateQuery_AllowMultiStatement(t *testing.T) {
	cfg := QuerySecurityConfig{
		AllowMultiStatement: true,
	}
	// With AllowMultiStatement=true, semicolons should be allowed everywhere
	queries := []string{
		"SELECT 1; SELECT 2",
		"INSERT INTO t VALUES(1); DELETE FROM t",
		"BEGIN proc1(); END; BEGIN proc2(); END;",
	}
	for _, q := range queries {
