func TestValidateQuery_RealWorldPatterns(t *testing.T) {
	cases := []struct {
		name  string
		query string
		ok    bool
	}{
		{
			"parameterized select",
			"SELECT * FROM employees WHERE employee_id = :id AND hire_date = :date",
			true,
		},
		{
			"insert with params",
			"INSERT INTO employees (id, name, hire_date) VALUES (:id, :name, :hire_date)",
			true,
		},
		{
			"update with params",
			"UPDATE employees SET name = :name WHERE id = :id",
			true,
		},
		{
			"procedure call",
			"BEGIN my_package.my_proc(:p_input, :p_output); END;",
			true,
		},
		{
			"procedure with multiple calls",
			"BEGIN pkg.proc1(:a); pkg.proc2(:b, :c); END;",
			true,
		},
		{
			"complex DECLARE block",
			"DECLARE v_count NUMBER; BEGIN SELECT COUNT(*) INTO v_count FROM employees; :result := v_count; END;",
			true,
		},
		{
			"select with subquery",
			"SELECT * FROM (SELECT id, name FROM employees WHERE dept_id = :dept) WHERE ROWNUM <= :limit",
			true,
		},
		{
			"merge statement",
			"MERGE INTO target t USING source s ON (t.id = s.id) WHEN MATCHED THEN UPDATE SET t.name = s.name WHEN NOT MATCHED THEN INSERT (id, name) VALUES (s.id, s.name)",
