package util

import (
	"context"
	"encoding/base64"
	"fec_pool_service/internal/dto"
	"fmt"
	"regexp"
	"strconv"
	"strings"
	"time"

	"github.com/bytedance/sonic"
	"github.com/google/uuid"
	"google.golang.org/grpc/metadata"
	"google.golang.org/protobuf/types/known/anypb"
	"google.golang.org/protobuf/types/known/wrapperspb"
)

func GenTransID() string {
	return uuid.New().String()
}

func ConvertStrToInt8(input string) int8 {
	result, err := strconv.ParseInt(input, 10, 8)
	if err == nil {
		return int8(result)
	}
	return 0
}

func ConvertStrToInt32(input string) int32 {
	result, err := strconv.ParseInt(input, 10, 32)
	if err == nil {
		return int32(result)
	}
	return 0
}

func NVL[T comparable](value *T, defaultValue T) T {
	if value == nil {
		return defaultValue
	}
	return *value
}

func GetClientID(ctx context.Context) string {
	if md, ok := metadata.FromIncomingContext(ctx); ok {
		authorization, ok := md["authorization"]
		if !ok {
			return ""
		}
		authorizationArrays := strings.Split(authorization[0], " ")
		if authorizationArrays[0] != "Basic" {
			return ""
		}
		usernameAndPassword, err := base64.StdEncoding.DecodeString(authorizationArrays[1])
		if err != nil {
			return ""
		}
		usernameAndPasswordArrays := strings.Split(string(usernameAndPassword), ":")
		if len(usernameAndPasswordArrays) != 2 {
			return ""
		}
		return usernameAndPasswordArrays[0]
	} else {
		return ""
	}
}

func ConvertArgs(args []*anypb.Any) []interface{} {
	result := make([]interface{}, len(args))
	for i, arg := range args {
		var value interface{}
		switch arg.TypeUrl {
		case "type.googleapis.com/google.protobuf.Int32Value":
			intVal := &wrapperspb.Int32Value{}
			if err := arg.UnmarshalTo(intVal); err != nil {
				value = arg.String()
			} else {
				value = int(intVal.GetValue())
			}
		case "type.googleapis.com/google.protobuf.StringValue":
			strVal := &wrapperspb.StringValue{}
			if err := arg.UnmarshalTo(strVal); err != nil {
				value = arg.String()
			} else {
				value = strVal.GetValue()
			}
		default:
			value = arg.String()
		}
		result[i] = value
	}
	return result
}

func Contains(slice []int, item int) bool {
	for _, v := range slice {
		if v == item {
			return true
		}
	}
	return false
}

func ToJSON(outParams map[string]interface{}) (string, error) {
	type CursorOutput struct {
		//ColumnNames []string            `json:"column_names"`
		Rows []map[string]string `json:"rows"`
	}
	type ExecuteOutput struct {
		OutParams map[string]interface{} `json:"out_params"`
	}

	output := ExecuteOutput{
		OutParams: make(map[string]interface{}),
	}

	for key, value := range outParams {
		switch v := value.(type) {
		case dto.CursorResult:
			rows := make([]map[string]string, len(v.Rows))
			for i, row := range v.Rows {
				rowData := make(map[string]string)
				for col, val := range row {
					switch valTyped := val.(type) {
					case time.Time:
						rowData[col] = valTyped.Format(time.RFC3339)
					default:
						rowData[col] = fmt.Sprint(valTyped)
					}
				}
				rows[i] = rowData
			}
			output.OutParams[key] = CursorOutput{
				//ColumnNames: v.ColumnNames,
				Rows: rows,
			}
		case time.Time:
			output.OutParams[key] = v.Format(time.RFC3339)
		default:
			output.OutParams[key] = v
		}
	}

	jsonstr, err := sonic.MarshalString(output)
	if err != nil {
		return "", fmt.Errorf("error when convert JSON byte array: %v", err)
	}
	return jsonstr, nil
}

func ProtectLiterals(query string) (string, map[string]string) {
	var sqlStringLiteralRegex = regexp.MustCompile(`'[^']*(?:''[^']*)*'`)

	literals := make(map[string]string)
	i := 0
	protectedQuery := sqlStringLiteralRegex.ReplaceAllStringFunc(query, func(match string) string {
		placeholder := fmt.Sprintf("__LITERAL_%d__", i)
		literals[placeholder] = match
		i++
		return placeholder
	})
	return protectedQuery, literals
}

func RestoreLiterals(query string, literals map[string]string) string {
	for placeholder, original := range literals {
		query = strings.ReplaceAll(query, placeholder, original)
	}
	return query
}

func TruncatedString(s string, limit int) string {
	if len(s) <= limit {
		return s
	}
	return s[:limit] + "...(truncated)"
}

