syntax = "proto3";
option go_package = ".;pb";

package pb;

import "protoc-gen-openapiv2/options/annotations.proto";
import "validate/validator.proto";

message PoolSysReq {
    string trans_id = 1[
        json_name = "TransID",
        (validate.rules).string.uuid = true,
        (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
            description: "TransactionID, must be unique and should follow UUID standard. Example: c9ee1cc1-5a2b-474d-84e0-13d6482d1570"
        }
    ];
    string requestor_id = 2[
        json_name = "RequestorID",
        (validate.rules).string.min_len = 1,
        (validate.rules).string.max_len = 100,
        (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
            description: "Caller system ID, example: PEGA, VTIGER, CMS"
        }
    ];
    string date_time = 3[
        json_name = "DateTime",
        (validate.rules).string = {pattern: "^\\d{4}-\\d{2}-\\d{2}[T\\s]\\d{2}:\\d{2}:\\d{2}(?:\\.\\d{1,9})?(?:Z(?:\\d{2}(?::?\\d{2})?)?|[+-]\\d{2}(?::?\\d{2})?)?$"},
        (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
            description: "Date time as string, accept RFC3339 or RFC3339Nano format. Example: \n"
            "   - 2025-03-24T11:13:55+07:00\n"
            "   - 2025-03-24T11:13:55+0700\n"
            "   - 2025-03-24T11:13:55.766+07:00\n"
            "   - 2025-03-24T11:13:55.766Z0700\n"
            "   - 2025-03-24T11:13:55.766Z07:00\n"
            "   - 2025-09-26T09:41:34\n"
            "   - 2025-09-26T09:41:34.999999999\n"
        }
    ];
}

message PoolSysResp {
    string trans_id = 1[json_name = "TransID"] ;
    string date_time = 2[json_name = "DateTime"] ;
    int32 code = 3[json_name = "Code"] ;
    string description = 4[json_name = "Description"] ;
}

message PoolExecuteQueryRequest {
    message QueryParameter {
        string name = 1[
            json_name = "Name",
            (validate.rules).string = {min_len: 1},
            (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
                description: "Name of parameter. example :id"
            }
        ];         
        string value = 2[
            json_name = "Value",
            (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
                description: "String value of parameter. Null use for output parameter "
            }
        ];        
        string data_type = 3 [
            json_name = "DataType",
            (validate.rules).string = {
                in: ["NUMBER", "VARCHAR2", "FLOAT", "DATE", "TIMESTAMP", "CURSOR", "CLOB", "BLOB"]
            },
            (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
                description: 
                "Data type value of parameter.\n"
                "Example: NUMBER.\n"
                "Use combination value null and datatype CURSOR for procedure output cursor.\n"
                "Must be one of these values:\n"
                "  - NUMBER\n"
                "  - VARCHAR2\n"
                "  - FLOAT\n"
                "  - DATE\n"
                "  - TIMESTAMP\n"
                "  - CURSOR"
            }
        ];    
    }
    PoolSysReq sys=1 [
        json_name = "Sys",
        (validate.rules).message.required=true
    ];
    string query_string = 2[
        json_name = "QueryString",
        (validate.rules).string = {min_len: 1},
        (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
            description: "Query string, must not empty. Example: SELECT * FROM employees WHERE employee_id = :id AND hire_date = :date"
        }
    ];
    repeated QueryParameter input_parameters = 3 [json_name = "InputParameters"];
    repeated QueryParameter input_output_parameters = 4[json_name = "InputOutputParameters"];
    repeated QueryParameter output_parameters = 5[json_name = "OutputParameters"];
}

message PoolExecuteQueryResponse {
    PoolSysResp sys = 1 [json_name = "Sys"];
    string results = 2[json_name = "Results"];
}

